from flask import Flask, redirect, url_for, session, request
from flask.json import jsonify
import requests
import jwt
import os

app = Flask(__name__)
app.secret_key = os.urandom(24)

CLIENT_ID = 'your_client_id'
CLIENT_SECRET = 'your_client_secret'
REDIRECT_URI = 'http://localhost:5000/callback'
AUTHORIZATION_URL = 'https://provider.com/oauth2/authorize'
TOKEN_URL = 'https://provider.com/oauth2/token'
USERINFO_URL = 'https://provider.com/userinfo'

@app.route('/')
def index():
    if 'user' in session:
        return f"Hello, {session['user']['name']}!"
    return 'You are not logged in. <a href="/login">Login</a>'

@app.route('/login')
def login():
    return redirect(f"{AUTHORIZATION_URL}?response_type=code&client_id={CLIENT_ID}&redirect_uri={REDIRECT_URI}&scope=openid")

@app.route('/callback')
def callback():
    code = request.args.get('code')
    token_response = requests.post(TOKEN_URL, data={
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': REDIRECT_URI,
        'client_id': CLIENT_ID,
        'client_secret': CLIENT_SECRET,
    })
    
    token_data = token_response.json()
    id_token = token_data['id_token']
    
    decoded_token = jwt.decode(id_token, options={"verify_signature": False})
    session['user'] = {
        'name': decoded_token.get('name'),
        'email': decoded_token.get('email')
    }
    
    return redirect(url_for('index'))

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=True)